```rust
use std::collections::BinaryHeap;

fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let k = k as usize;

    let mut teleport = vec![vec![vec![]; n]; m];
    for i in 0..m {
        for j in 0..n {
            let current_val = grid[i][j];
            for x in 0..m {
                for y in 0..n {
                    if grid[x][y] <= current_val {
                        teleport[i][j].push((x, y));
                    }
                }
            }
        }
    }

    let mut dist = vec![vec![vec![i64::MAX; k + 1]; n]; m];
    dist[0][0][0] = 0;

    let mut heap = BinaryHeap::new();
    heap.push((0, 0, 0, 0));

    while let Some((cost, i, j, t)) = heap.pop() {
        if i == m - 1 && j == n - 1 {
            return cost;
        }
        if cost > dist[i][j][t] {
            continue;
        }

        // Regular moves
        if j + 1 < n {
            let new_cost = cost + grid[i][j + 1];
            if new_cost < dist[i][j + 1][t] {
                dist[i][j + 1][t] = new_cost;
                heap.push((new_cost, i, j + 1, t));
            }
        }
        if i + 1 < m {
            let new_cost = cost + grid[i + 1][j];
            if new_cost < dist[i + 1][j][t] {
                dist[i + 1][j][t] = new_cost;
                heap.push((new_cost, i + 1, j, t));
            }
        }

        // Teleportation
        if t < k {
            for (x, y) in &teleport[i][j] {
                let new_t = t + 1;
                if cost < dist[*x][*y][new_t] {
                    dist[*x][*y][new_t] = cost;
                    heap.push((cost, *x, *y, new_t));
                }
            }
        }
    }

    i64::MAX
}
